      }
    } catch (err) {
      console.warn('[ai] Whisper failed, using browser transcription:', err.message);
    }
  }

  // Step 2: Run all analyses in parallel
  const analysisPromises = [
    analyzeInterviewResponse(question, finalTranscription, keyPoints, options),
